INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Document versioning$q$, $q$Maintain and publish multiple versions of documentation side by side so users on older software releases still see accurate docs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$MDX support$q$, $q$Write Markdown content that can embed live, interactive React components directly inside documentation pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Built-in internationalization$q$, $q$Translate docs into multiple languages using Git-based workflows or integrations like Crowdin, with locale-aware routing out of the box.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Plugin and theme architecture$q$, $q$Extend or customize nearly any part of the site through a documented plugin API and swappable themes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Integrated blog engine$q$, $q$Publish a changelog or company blog alongside documentation using the same content pipeline.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Algolia DocSearch and AI search$q$, $q$Add fast full-text search to a documentation site, including an AI-powered search assistant introduced in recent versions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Static site output$q$, $q$Compiles to plain HTML, CSS, and JavaScript with no server or database required, making hosting simple and inexpensive.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Accessibility and SEO defaults$q$, $q$Ships with sensible accessibility and SEO defaults, including sitemaps, meta tags, and semantic markup.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Completely free and open-source with no licensing costs or usage caps.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Purpose-built for documentation, including versioning and sidebar navigation out of the box.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Backed by Meta's engineering organization and a large, active open-source community.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$MDX support allows interactive, component-driven documentation rather than plain static text.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Requires comfort with Node.js tooling, Git, and (for customization) React and JavaScript.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$No built-in CMS or non-technical editing interface; content is managed as files in a repository.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Best suited to documentation-style content rather than general marketing or e-commerce sites.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Self-managed hosting and deployment mean teams are responsible for their own build pipeline and uptime.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Is Docusaurus free to use?$q$, $q$Yes. Docusaurus is fully open-source under the MIT license with no paid tiers; the only cost is whatever static hosting provider you choose to deploy the generated site on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Who created Docusaurus?$q$, $q$Docusaurus was created by Facebook (now Meta) in 2017 to standardize documentation across its open-source projects, and it is maintained by Meta's Open Source team alongside community contributors.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Do I need to know React to use Docusaurus?$q$, $q$No. Most content is written in Markdown or MDX, so non-technical writers can contribute without React knowledge, though React skills help when customizing themes or building interactive components.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Can Docusaurus host versioned documentation?$q$, $q$Yes, versioning is a built-in feature, allowing a project to publish and switch between docs for multiple software releases simultaneously.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$What is the difference between Docusaurus 1 and 2?$q$, $q$Docusaurus 2.0, released in 2022, was a full rewrite on React with MDX support, a plugin system, and a more flexible theming architecture compared to the original 2017 version.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$What are the main alternatives to Docusaurus?$q$, $q$Common alternatives include MkDocs (with the Material theme), GitBook, ReadMe, VitePress, Nextra, and Sphinx, depending on whether a team prioritizes Markdown simplicity, hosted convenience, or React-based customization.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Open-source project documentation$q$, $q$Maintain versioned, searchable docs alongside the codebase in the same Git repository, with pull-request-based review for content changes.$q$, $q$Open-source maintainers and contributors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Developer tool and API documentation$q$, $q$Publish public-facing developer guides and API references with custom interactive components embedded via MDX.$q$, $q$Developer relations and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Internal engineering knowledge bases$q$, $q$Host internal technical documentation that is easy to keep current because it lives in version control next to the code it describes.$q$, $q$Internal engineering and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited sites and pages","Self-hosted, no vendor lock-in","Community support via GitHub and Discord"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Docusaurus is a free, open-source static site generator created by Meta specifically for building documentation websites, product guides, and blogs. It turns Markdown and MDX content into a fast, versioned, searchable React-powered site.$q$, $q$Originally built in 2017 to standardize documentation across Facebook's many open-source projects, Docusaurus was rewritten from the ground up in 2022 (version 2.0) and has continued to add capabilities like TypeScript support and AI-assisted search in subsequent releases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Docusaurus ships with document versioning, sidebar-based navigation, MDX support for embedding interactive React components in Markdown, built-in internationalization, dark mode, a blog engine, and a plugin/theme architecture for extending the platform.$q$, $q$Because the generated output is static HTML, sites built with Docusaurus load quickly, are easy to cache on a CDN, and are naturally friendly to search engine crawlers without extra SEO configuration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Docusaurus is completely free and open-source under the MIT license, with no paid tiers, feature gates, or usage limits from the project itself.$q$, $q$The only ongoing cost is static hosting, and providers such as Netlify, Vercel, GitHub Pages, and Cloudflare Pages all offer free plans that comfortably cover most documentation sites, including open-source and small commercial projects.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7736f4e7-14df-4b55-a27c-530d35d06fd1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Multi-party e-signatures$q$, $q$Send documents to multiple signers in a defined order and track each signer's completion status in real time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Template builder$q$, $q$Create reusable document templates with drag-and-drop fields, or auto-detect fields from an uploaded PDF.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Self-hosted deployment$q$, $q$Run the entire open-source platform on your own infrastructure via Docker for full data control and compliance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$API and webhooks$q$, $q$Programmatically create, send, and track documents, and receive real-time status updates via webhooks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Advanced signature types$q$, $q$Support for EU Advanced Electronic Signatures (AES) and Qualified Electronic Signatures (QES) for regulated use cases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$SSO/SAML and SMS verification$q$, $q$Enterprise authentication options including single sign-on and SMS-based signer identity verification.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Bulk send$q$, $q$Send the same document template to many recipients at once from an uploaded spreadsheet.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$White-labeling$q$, $q$Remove DocuSeal branding and apply company logos and custom email domains on Pro plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Free, fully functional open-source self-hosted edition with no per-signature fees for core use.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Pro pricing at $20/user/month undercuts most established commercial e-signature vendors.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Full data control and compliance flexibility for organizations that self-host.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Developer-friendly with a documented API, webhooks, and Zapier support.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$As a small, newer company, enterprise support and compliance certifications are less mature than large incumbents.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Self-hosting requires technical setup and ongoing server maintenance.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Advanced signature types (QES) and API completions carry additional per-use fees beyond the subscription.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Free cloud plan is capped at a limited number of monthly signature requests.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Is DocuSeal really free?$q$, $q$Yes, DocuSeal offers both a free cloud Basic plan with limited monthly requests and a fully free, open-source self-hosted Community edition with no per-signature charges.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$How much does DocuSeal Pro cost?$q$, $q$DocuSeal Pro costs $20 per user per month on both the cloud and self-hosted tracks, with an annual billing discount available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Can DocuSeal be self-hosted?$q$, $q$Yes, DocuSeal is released under the AGPLv3 open-source license and can be deployed on your own servers using Docker for complete control over data storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Are DocuSeal signatures legally binding?$q$, $q$Yes, DocuSeal supports legally binding electronic signatures, including EU-recognized Advanced and Qualified Electronic Signatures on paid tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Who founded DocuSeal?$q$, $q$DocuSeal was founded in 2023 by developer Alex Turin as a bootstrapped, open-source alternative to established e-signature platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$What is the difference between DocuSeal and DocuSign?$q$, $q$DocuSeal is open-source and can be self-hosted at no licensing cost, with lower per-user pricing on its Pro tier, while DocuSign is a larger public company with more extensive enterprise features, integrations, and compliance certifications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Embedded signing in a SaaS product$q$, $q$Use DocuSeal's API and embedding features to add native document-signing directly inside another application's workflow.$q$, $q$Software developers and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Compliance-sensitive document signing$q$, $q$Self-host DocuSeal to keep signed contracts and personal data entirely within an organization's own infrastructure.$q$, $q$Legal, healthcare, and regulated-industry teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Cost-effective contract signing for small business$q$, $q$Replace expensive per-seat e-signature subscriptions with DocuSeal's free or lower-cost cloud plans for routine contracts and forms.$q$, $q$Startups and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Basic (Cloud)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Legally binding e-signatures","Indefinite document retention","Multiple signers","10 field types","Limited signature requests per month","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Pro (Cloud)$q$, $q$$20/user/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Unlimited signature requests","Company branding","Automated reminders","Payment collection","Zapier and webhook integrations","SSO/SAML","API and embedding access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","Legally binding e-signatures","Multiple signers","Own SMTP for email","Community support via GitHub"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$Pro (Self-Hosted)$q$, $q$$20/user/month$q$, $q$monthly$q$, NULL, $q$["White-labeling","Full data control","Automation and integrations","SSO/SAML","API access","Account manager support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DocuSeal is an open-source electronic signature platform that lets teams create fillable document templates, collect legally binding signatures from multiple parties, and track completion status, either through DocuSeal's hosted cloud service or a fully self-hosted deployment.$q$, $q$Founded in 2023 and headquartered in Chicago, DocuSeal has grown quickly as a lower-cost, self-hostable alternative to established e-signature vendors, backed by an active open-source community on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DocuSeal supports a full document-signing workflow: template creation from uploaded PDFs, ten-plus field types, multi-party signing order, automated reminders, and tamper-evident signed PDFs with audit trails.$q$, $q$Advanced capabilities include API access, webhook and Zapier integrations, bulk sending, SSO/SAML, SMS-based identity verification, and support for EU-recognized Advanced and Qualified Electronic Signatures.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DocuSeal offers a free Basic cloud plan and a free open-source Community self-hosted edition, both covering core signing functionality with limited monthly requests on the cloud side.$q$, $q$The Pro tier, available on both cloud and self-hosted deployments, costs $20 per user per month and adds branding, automation, integrations, and advanced authentication, with usage-based add-on fees for QES, ID verification, and API completions.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fed2af81-3cbf-403c-8135-b548f382e7ac', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Multi-party e-signature workflows$q$, $q$Route documents to multiple signers in a defined order with real-time status tracking for each recipient.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Identity verification options$q$, $q$Authenticate signers via email, SMS, government ID checks, or knowledge-based authentication for higher-assurance signing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Reusable templates$q$, $q$Save frequently used documents as templates with pre-placed fields to speed up repeated sending.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Audit trail and certificate of completion$q$, $q$Every signed document includes a tamper-evident audit trail documenting signer identity, timestamps, and IP addresses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Contract lifecycle management (CLM)$q$, $q$Manage agreements beyond signing, including negotiation, storage, and AI-assisted contract analysis on higher tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Enterprise integrations$q$, $q$Native integrations with Salesforce, Microsoft 365, Google Workspace, SAP, and Workday, plus a public API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Mobile signing app$q$, $q$Sign and send documents from iOS and Android devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Bulk send and payment collection$q$, $q$Send the same document to many recipients at once and collect payments during the signing process on Business Pro and above.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Widely recognized and trusted brand with the broadest range of enterprise integrations in the category.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Supports the widest range of international e-signature and compliance standards among mainstream vendors.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Scales from single-user Personal plans up to large enterprise agreement lifecycle management.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Mature mobile apps and identity verification options for higher-assurance signing needs.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Meaningfully more expensive than newer competitors, especially open-source alternatives.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Standard and Business Pro plans cap included envelopes at 100 per user per year, with overage or upgrade required beyond that.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Add-on fees for SMS delivery, ID verification, and premium support can push real costs above the advertised price.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Enterprise pricing is not published and requires a custom sales quote.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$How much does DocuSign cost?$q$, $q$DocuSign starts at about $10/month for the Personal plan (billed annually), with Standard around $25/user/month, Business Pro around $40/user/month, and custom Enterprise pricing for large organizations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Who founded DocuSign and when?$q$, $q$DocuSign was founded in 2003 in Seattle by Court Lorenzini, Tom Gonser, and Eric Ranft, and later moved its headquarters to San Francisco.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Is DocuSign a public company?$q$, $q$Yes, DocuSign went public on the Nasdaq under the ticker DOCU on April 27, 2018, after raising about $520 million in venture funding.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Does DocuSign have envelope limits?$q$, $q$Yes, the Standard and Business Pro annual plans cap included envelopes at 100 per user per year; exceeding that can trigger overage fees or require a plan upgrade.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$What is the difference between DocuSign eSignature and DocuSign CLM?$q$, $q$eSignature covers sending and signing individual documents, while DocuSign's Contract Lifecycle Management (CLM) product manages the broader agreement process, including negotiation, storage, and AI-assisted analysis, typically as an add-on for larger organizations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$What are the best DocuSign alternatives?$q$, $q$Common alternatives include Adobe Acrobat Sign, PandaDoc, Dropbox Sign, SignNow, and open-source options like DocuSeal, which typically undercut DocuSign on price.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Sales contract signing$q$, $q$Send sales agreements and order forms for signature directly from a CRM like Salesforce, tracking completion status in real time.$q$, $q$Sales teams and account managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$HR onboarding paperwork$q$, $q$Collect signatures on offer letters, NDAs, and onboarding forms from new employees remotely.$q$, $q$HR and people operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Real estate and legal document execution$q$, $q$Route multi-party contracts such as leases, purchase agreements, and legal filings through a defined, auditable signing order.$q$, $q$Real estate agents, brokers, and legal professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Personal$q$, $q$$10/month (annual) / $15/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["1 user","Up to 5 envelopes per month","Basic e-signature workflow","Mobile app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Standard$q$, $q$$25/user/month (annual) / $45/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 100 envelopes per user/year","Custom branding","Reusable templates","Basic reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Business Pro$q$, $q$$40/user/month (annual) / $65/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Up to 100 envelopes per user/year","Bulk send","Payment collection","Advanced fields","Additional authentication options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$Enterprise / Advanced Solutions$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Identity verification","Conditional routing","Advanced API access","Salesforce and Workday integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DocuSign is the market-leading electronic signature and agreement management platform, allowing individuals and organizations to send, sign, and track legally binding documents entirely online.$q$, $q$Founded in 2003 and headquartered in San Francisco, DocuSign went public on the Nasdaq in 2018 and has since expanded from pure e-signature into a broader Intelligent Agreement Management platform covering the full contract lifecycle.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include multi-party signing workflows, identity verification, reusable templates, tamper-evident audit trails, and a mobile app for signing on the go.$q$, $q$Higher tiers add bulk sending, payment collection, contract lifecycle management, AI-assisted contract review, and deep integrations with Salesforce, Microsoft 365, and other enterprise systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DocuSign is priced per user per month across four tiers: Personal (around $10/month), Standard (around $25/user/month), Business Pro (around $40/user/month), and a custom-quoted Enterprise tier, all cheaper when billed annually.$q$, $q$Standard and Business Pro annual plans include a cap of 100 envelopes per user per year, and buyers should account for potential add-on fees like SMS delivery and ID verification when budgeting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21b62640-e209-4a01-b000-4e8484a033b6', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Git push deployment$q$, $q$Deploy applications with a single git push dokku main command, mirroring the classic Heroku workflow.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Automatic buildpack detection$q$, $q$Detects the application language and framework and builds it automatically using Heroku buildpacks, Cloud Native Buildpacks, Nixpacks, Railpack, or a Dockerfile.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Zero-downtime deployments$q$, $q$Routes traffic to a new container only after its health checks pass, avoiding service interruption during deploys.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Automatic SSL via Let's Encrypt$q$, $q$Provisions and renews free SSL certificates automatically for custom domains.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Plugin ecosystem$q$, $q$Hundreds of community plugins add databases, scheduled jobs, monitoring, and other capabilities to a base installation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Built-in reverse proxy$q$, $q$Uses nginx to route traffic, manage domains, and handle load balancing for deployed applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Environment variable and config management$q$, $q$Manage per-app environment variables and configuration through simple CLI commands.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Single-server efficiency$q$, $q$Runs comfortably on a single low-cost VPS, avoiding the operational overhead of a full Kubernetes cluster.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Completely free and open-source with no recurring licensing or platform fees.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Near-identical developer experience to Heroku, making migration away from Heroku straightforward.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Lightweight enough to run on a single inexpensive VPS, unlike heavier orchestration platforms.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Large plugin ecosystem covering databases, SSL, and other common infrastructure needs.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Requires the team to manage, patch, back up, and monitor their own server.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Primarily designed around single-host deployments, with more limited multi-host scaling than Kubernetes.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$No official managed hosting or enterprise support contract from a vendor.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Documentation and plugin quality can vary since many plugins are community-maintained.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Is Dokku free?$q$, $q$Yes, Dokku is completely free and open-source under the MIT license; the only cost is the server it runs on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Who created Dokku?$q$, $q$Dokku was created by developer Jeff Lindsay in 2013 and is now maintained by an open-source community on GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$How does Dokku deployment work?$q$, $q$Developers push code to Dokku via Git, and Dokku automatically detects the app type, builds a Docker image using a buildpack or Dockerfile, and runs it in a container behind an nginx reverse proxy.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Is Dokku a replacement for Heroku?$q$, $q$Dokku is commonly used as a self-hosted replacement for Heroku, replicating its git-push workflow without the recurring per-dyno fees, though it requires the team to manage its own server.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Can Dokku run multiple applications on one server?$q$, $q$Yes, a single Dokku installation can host and route traffic to many applications on one server, making it efficient for small-to-medium workloads.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$What are alternatives to Dokku?$q$, $q$Alternatives include managed platforms like Heroku, Render, Railway, and Fly.io, as well as other self-hosted options like CapRover and Coolify.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Self-hosted app deployment for side projects$q$, $q$Deploy personal or small commercial projects to a single low-cost VPS with Heroku-style simplicity.$q$, $q$Indie developers and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Heroku cost migration$q$, $q$Move existing Heroku applications to self-managed infrastructure to eliminate recurring per-dyno platform fees.$q$, $q$Startups and cost-conscious engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Internal tooling platform$q$, $q$Provide an internal, self-hosted deployment target for multiple small internal tools and services without standing up Kubernetes.$q$, $q$Small engineering teams and internal platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited apps per server","Community plugin ecosystem","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dokku is a free, open-source Platform-as-a-Service that lets developers deploy applications to their own server using the same git-push workflow popularized by Heroku.$q$, $q$Created in 2013 by Jeff Lindsay, Dokku has grown from a small shell script into a mature, plugin-based platform maintained by an open-source community, with no corporate owner or licensing fee.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dokku automatically builds applications using Heroku buildpacks, Cloud Native Buildpacks, Nixpacks, or raw Dockerfiles, then runs them in Docker containers with an nginx reverse proxy, automatic SSL via Let's Encrypt, and zero-downtime deployments.$q$, $q$A plugin architecture covers everything from database provisioning (PostgreSQL, MySQL, Redis, MongoDB) to scheduled jobs, letting teams extend a single-server deployment into a fairly complete self-hosted application platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dokku itself is entirely free and open-source under the MIT license, with no subscription, per-app, or per-dyno charges.$q$, $q$The only cost is the server infrastructure it runs on, which can be a single low-cost VPS, making Dokku significantly cheaper over time than managed PaaS platforms like Heroku for teams willing to manage their own server.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6cf17823-4f66-4f20-8ec7-a8927a750f25', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$No database required$q$, $q$Stores all pages and metadata as plain text files, simplifying installation, backup, and version control.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Automatic page versioning$q$, $q$Every edit is saved as a revision, allowing users to compare and revert to any prior version of a page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Fine-grained access control$q$, $q$Page- and namespace-level ACLs combined with a built-in user/group manager control who can read or edit content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$External authentication support$q$, $q$Integrates with LDAP, Active Directory, and other external authentication backends.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Large plugin ecosystem$q$, $q$Roughly 1,000 community-built plugins extend syntax, functionality, and integrations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Multilingual support$q$, $q$Ships with translations for around 70 languages, including full right-to-left language rendering.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Lightweight hosting requirements$q$, $q$Runs on any web server with PHP, making it suitable for low-cost or shared hosting environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Template system$q$, $q$Change the visual appearance of a wiki independently of its content and plugins.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Completely free and open-source with no licensing costs.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$No database dependency makes installation, backup, and migration simple.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Fine-grained, namespace-based access control beyond what many database-backed wikis offer.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Long track record of stability with over two decades of continuous development.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$File-based storage can become slower to search at very large page counts compared to database-backed wikis.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$User interface and editing experience feel dated compared to modern collaborative tools like Notion or Confluence.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$No official managed hosting or commercial support from the core project.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Plugin quality varies since most are community-maintained rather than officially vetted.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Is DokuWiki free?$q$, $q$Yes, DokuWiki is entirely free and open-source under the GPL license, with no paid tiers or usage restrictions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Does DokuWiki need a database?$q$, $q$No, DokuWiki stores all pages and metadata as plain text files on disk, which is one of its main differentiators from database-backed wikis like MediaWiki.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Who created DokuWiki?$q$, $q$DokuWiki was created by German developer Andreas Gohr, who began work on it in June 2004 to document his own system administration tasks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Can DokuWiki control who edits specific pages?$q$, $q$Yes, DokuWiki includes a built-in access control list system that can restrict read or write permissions at the individual page or namespace level.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$What languages does DokuWiki support?$q$, $q$DokuWiki has been translated into roughly 70 languages and includes full support for right-to-left languages such as Hebrew and Arabic.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$How is DokuWiki different from MediaWiki?$q$, $q$DokuWiki uses file-based storage and requires no database, while MediaWiki (which powers Wikipedia) requires a MySQL or MariaDB database and offers a larger extension ecosystem geared toward very large-scale wikis.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Internal IT documentation$q$, $q$Document infrastructure, procedures, and runbooks in a lightweight wiki that is easy to back up alongside server configuration.$q$, $q$System administrators and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Small team knowledge base$q$, $q$Give a small organization a searchable, versioned internal knowledge base without standing up a database server.$q$, $q$Small businesses and nonprofit organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Software project documentation$q$, $q$Host user manuals and technical documentation for a software project with fine-grained edit permissions.$q$, $q$Open-source and software development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited pages and namespaces","Access control lists","Community plugin and template ecosystem"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DokuWiki is a free, open-source wiki engine notable for storing all content as plain text files rather than in a database, making it exceptionally simple to install, back up, and maintain.$q$, $q$Created by Andreas Gohr in 2004 for his own sysadmin documentation needs, DokuWiki has been continuously developed for over two decades and remains a popular choice for lightweight, self-hosted knowledge bases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DokuWiki requires only a web server and PHP, with automatic page versioning, namespace-based organization, and fine-grained access control lists at the page and namespace level.$q$, $q$A generic plugin interface supports roughly a thousand community plugins, and built-in internationalization covers around 70 languages, including proper right-to-left text rendering.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DokuWiki is completely free and open-source under the GPL license, with no paid tiers or usage limits from the project itself.$q$, $q$Because it requires no database server, it can run on inexpensive shared hosting, keeping total hosting costs low compared to database-dependent wiki platforms.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bac55456-ac21-473d-a96f-b37ba84bb107', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Modular activation$q$, $q$Enable only the specific business modules a company needs, from invoicing to HR, without installing unused functionality.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Invoicing and quotes$q$, $q$Create customer and supplier invoices, commercial proposals, and recurring billing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Order and inventory management$q$, $q$Track product and service catalogs, stock levels across warehouses, and purchase and sales orders.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Built-in CRM$q$, $q$Manage contacts, leads, and sales opportunities within the same system as invoicing and orders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Point of sale (POS)$q$, $q$Run in-person retail sales through a built-in point-of-sale module.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$HR and project management$q$, $q$Track employee leave, expenses, and project tasks alongside core financial data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Accounting module$q$, $q$Manage bookkeeping and financial reporting natively within the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Flexible hosting$q$, $q$Self-host on any PHP/MySQL server or use the official DoliCloud managed SaaS hosting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Completely free, open-source core with no seat limits or feature paywalls.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Highly modular, so businesses only enable and configure what they actually need.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Broad functional coverage (invoicing, CRM, inventory, HR, accounting) in a single lightweight platform.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Affordable official managed hosting option (DoliCloud) for teams that don't want to self-host.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Smaller module and integration ecosystem than larger open-source ERPs like Odoo.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Interface and UX are more utilitarian than modern commercial SaaS competitors.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Advanced manufacturing and complex supply-chain features are less developed than dedicated ERP suites.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Self-hosting requires ongoing server maintenance, backups, and update management.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Is Dolibarr free to use?$q$, $q$Yes, Dolibarr's core ERP/CRM software is free and open-source under the GPL license, with optional costs only for hosting, premium modules, or professional support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Who created Dolibarr?$q$, $q$Dolibarr was created by French developer Rodolphe Quiedeville, who started the project in April 2002, with the first release in September 2003.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Can Dolibarr be self-hosted?$q$, $q$Yes, Dolibarr is a standard PHP and MySQL/MariaDB web application that can be installed on any compatible server, or accessed through the official DoliCloud managed hosting service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$What modules does Dolibarr include?$q$, $q$Dolibarr offers modules for invoicing, quotes, order management, inventory, point-of-sale, CRM, project management, HR, accounting, and a lightweight CMS, all independently activatable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$How much does DoliCloud hosting cost?$q$, $q$DoliCloud, the official managed hosting service, starts at roughly 9 euros per month, with a Premium tier around 30 euros per month plus a per-user fee for additional users.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$How does Dolibarr compare to Odoo?$q$, $q$Dolibarr is generally lighter-weight and simpler to set up than Odoo, while Odoo offers a larger module ecosystem and more advanced manufacturing and supply-chain features at greater complexity and cost.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Small business invoicing and order management$q$, $q$Manage quotes, invoices, and customer orders in one system without paying for a commercial ERP license.$q$, $q$Small businesses and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Nonprofit and association management$q$, $q$Track members, donations, projects, and finances using Dolibarr's flexible modular structure.$q$, $q$Nonprofits and foundations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Integrated retail and inventory operations$q$, $q$Combine point-of-sale, inventory tracking, and accounting for a small retail business.$q$, $q$Retail and small commerce operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","All standard modules","Unlimited users","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$DoliCloud Basic$q$, $q$~9 EUR/month$q$, $q$monthly$q$, NULL, $q$["Managed hosting","Automatic updates and backups","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$DoliCloud Premium$q$, $q$~30 EUR/month + ~12 EUR/user/month$q$, $q$monthly$q$, NULL, $q$["Managed hosting","Priority support","Additional user seats","Automatic updates and backups"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dolibarr is a free, open-source ERP and CRM web application that lets small and medium businesses manage invoicing, orders, inventory, HR, and other core operations through independently activatable modules.$q$, $q$Started in 2002 by Rodolphe Quiedeville and now governed by the France-based Dolibarr Association, the project has been downloaded more than five million times and is used in over 60 countries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dolibarr's modular design covers invoicing, quotes, order and stock management, point-of-sale, CRM, project management, HR, accounting, and even a built-in CMS, letting businesses enable only what they need.$q$, $q$As a standard PHP and MySQL/MariaDB application, Dolibarr can be self-hosted on any LAMP-compatible server or accessed through the official DoliCloud SaaS hosting service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dolibarr's core software is completely free and open-source under the GPL license, with no seat limits or feature paywalls.$q$, $q$Optional costs come from self-hosting infrastructure, premium marketplace modules, professional services, or the official DoliCloud managed hosting, which starts at roughly 9 euros per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('da85131f-6520-4e7e-b70d-0a49a665a0fa', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Centralized domain dashboard$q$, $q$Track every domain across all registrars in a single interface regardless of where each was purchased.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Expiry and change alerts$q$, $q$Receive configurable notifications for upcoming expirations and DNS or WHOIS changes via email, webhook, push, Telegram, or Signal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Valuation and cost tracking$q$, $q$Monitor purchase price, renewal cost, and estimated current valuation to track portfolio profit and loss.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$AI domain name ideas$q$, $q$Generate new domain name suggestions and check availability using built-in AI-assisted tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$API and integrations$q$, $q$Access domain data via a REST API, Prometheus metrics, iCal calendar feeds, RSS, and embeddable widgets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Self-hosted deployment$q$, $q$Run the entire open-source platform on your own infrastructure via Docker with full data control.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$SSO and 2FA$q$, $q$Sign in via GitHub or Google single sign-on, with two-factor authentication for added account security.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Web analysis and auditing$q$, $q$Run enterprise-style analysis and audits on tracked domains for deeper technical insight.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Registrar-agnostic, tracking domains purchased anywhere in one unified dashboard.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Fully free, open-source self-hosted edition includes all Pro-tier features.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Developer-friendly with API, Prometheus, and webhook integrations for existing monitoring stacks.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Low starting price for the cloud tiers compared to enterprise domain/brand-protection platforms.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Self-hosted deployment requires Docker knowledge and ongoing server maintenance.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Self-hosted edition lacks built-in email and push notifications without extra configuration.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$As a young project, its long-term company backing and support infrastructure are less established than larger competitors.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Cloud plan domain limits (5/20/100) may require upgrades for larger domain portfolios.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Is Domain Locker free?$q$, $q$Yes, Domain Locker offers a free cloud plan for up to 5 domains, and its self-hosted edition is entirely free and open-source with all Pro-tier features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Who created Domain Locker?$q$, $q$Domain Locker was created by London-based developer Alicia Sykes (Lissy93), who has built a range of free and open-source software projects.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Can Domain Locker be self-hosted?$q$, $q$Yes, Domain Locker can be self-hosted using Docker and Docker Compose, giving users full control over their data and infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$How much do Domain Locker's paid plans cost?$q$, $q$The Hobby plan costs $5/month (billed annually) for up to 20 domains, and the Pro plan costs $20/month (billed annually) for up to 100 domains.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Does Domain Locker work with any domain registrar?$q$, $q$Yes, Domain Locker is registrar-agnostic and can track domains regardless of where they were originally purchased.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$What notification channels does Domain Locker support?$q$, $q$Domain Locker can send alerts via email, webhook, push notification, Telegram, and Signal, in addition to in-app notifications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Domain investor portfolio tracking$q$, $q$Monitor renewal costs, valuations, and profit/loss across a large portfolio of domains held for investment.$q$, $q$Domain investors and portfolio holders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Agency client domain management$q$, $q$Track expiry dates and DNS changes for many client domains from a single centralized dashboard.$q$, $q$Web development and digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Self-hosted privacy-focused monitoring$q$, $q$Deploy Domain Locker on personal infrastructure to monitor domains without relying on a third-party cloud service.$q$, $q$Privacy-conscious self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Up to 5 domains","Basic domain info","Expiry email alerts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Hobby$q$, $q$$5/month$q$, $q$billed annually$q$, NULL, $q$["Up to 20 domains","Detailed domain info","Change notifications","Domain change history","Statistics and alerts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Pro$q$, $q$$20/month$q$, $q$billed annually$q$, NULL, $q$["Up to 100 domains","Advanced statistics","Advanced alerts","Domain monitoring"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["All Pro features","Full source code access","Docker deployment","Self-managed infrastructure"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Domain Locker is an open-source, registrar-agnostic domain portfolio management app that centralizes expiry tracking, DNS monitoring, valuations, and change alerts for every domain a user owns.$q$, $q$Built by London-based developer Alicia Sykes (Lissy93) and released under the MIT license, it offers both a hosted cloud service and a free, Docker-deployable self-hosted edition.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The app tracks purchase price, renewal cost, and estimated valuation, sends configurable alerts for expirations and DNS/WHOIS changes via email, webhook, push, Telegram, or Signal, and includes AI-assisted domain name ideas and availability search.$q$, $q$Data is accessible via a REST API, Prometheus metrics, iCal feeds, RSS, and embeddable widgets, with SSO via GitHub or Google and two-factor authentication for account security.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Domain Locker's cloud plans range from a Free tier (5 domains) to Hobby at $5/month (20 domains) and Pro at $20/month (100 domains), all billed annually.$q$, $q$A fully free, open-source self-hosted edition offers all Pro-tier features for users willing to run and maintain their own Docker deployment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
