INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('03502625-329e-43e5-b9a4-c57308f6f0a3', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Automated submission judging$q$, $q$Compiles and runs contestant code against jury-defined test cases and automatically determines the verdict (accepted, wrong answer, time limit exceeded, etc.).$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Distributed judging$q$, $q$Scales judging across multiple machines running in parallel to keep queues short during high-submission-volume contests.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Team, jury, and public interfaces$q$, $q$Separate web interfaces let teams submit and view results, juries manage problems and clarifications, and the public follow a live scoreboard.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Modular language support$q$, $q$Add support for additional programming languages or compilers through the system's pluggable language architecture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Clarification request system$q$, $q$Handles structured communication between contestant teams and the jury during a live contest.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Command-line and web submission$q$, $q$Contestants can submit solutions through either a command-line client or a web-based interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Live ranked scoreboard$q$, $q$Displays a real-time, publicly viewable scoreboard ranking teams by problems solved and penalty time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Self-hosted deployment$q$, $q$Runs on a standard Linux, PHP, and MySQL/MariaDB stack under an organization's own infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Completely free and open-source with no licensing costs.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Long, proven track record as trusted judging infrastructure across many ICPC regional contests.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Distributed judging architecture scales to handle high-volume submission traffic during live contests.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Modular language support makes it adaptable to a wide range of contest formats and requirements.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$No official managed hosting or SaaS option; organizers must set up and maintain their own servers.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Interface and workflow are purpose-built for competitive programming contests rather than general-purpose use.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Requires technical setup, including judge machine configuration for isolated code execution.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Smaller maintainer community compared to broader open-source projects, though highly specialized and stable.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Is DOMJudge free to use?$q$, $q$Yes, DOMJudge is fully open-source under the GPL-2.0 license and free to download, install, and run with no licensing fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Who created DOMJudge?$q$, $q$DOMJudge originated in 2004 with the computer science student association at Utrecht University in the Netherlands and has since been maintained by an international open-source community.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$What contests use DOMJudge?$q$, $q$DOMJudge is used in numerous ICPC regional contests, including NWERC and SWERC, as well as university courses and other competitive programming events worldwide.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$What does DOMJudge require to run?$q$, $q$DOMJudge requires a Linux server with PHP 7.4 or newer, a MySQL or MariaDB database, and compilers for whichever programming languages the contest will support.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Does DOMJudge support multiple programming languages?$q$, $q$Yes, its modular architecture lets contest organizers plug in support for additional languages and compilers as needed.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$What are alternatives to DOMJudge?$q$, $q$Alternatives include PC^2, Kattis, Codeforces' judging infrastructure, and CMS (Contest Management System), which is more commonly used for olympiad-style informatics competitions.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$ICPC regional contest judging$q$, $q$Run the full submission, judging, and live scoreboard workflow for a regional or university-level ICPC-style programming contest.$q$, $q$University programming contest organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$University coursework and practice contests$q$, $q$Use DOMJudge as courseware to give students automated feedback on programming exercises and practice contests.$q$, $q$Computer science instructors and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Internal company coding competitions$q$, $q$Set up a self-hosted judging system for internal hackathons or coding challenges within an organization.$q$, $q$Engineering teams and coding bootcamps$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Unlimited contests and submissions","Distributed judging support","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DOMJudge is a free, open-source automated judging system for running programming contests, most notably regional events of the ACM ICPC, handling submission compilation, execution, output comparison, and scoring.$q$, $q$First committed in May 2004 and originating from the computer science student association at Utrecht University, DOMJudge has grown into the de facto standard judge used across many ICPC regionals worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The system automatically compiles and runs contestant submissions against jury-defined test cases, supports distributed judging across multiple machines, and offers separate web interfaces for teams, jury members, and public scoreboards.$q$, $q$Its modular design lets contest organizers add support for additional programming languages and compilers, and it handles clarification-request communication between teams and the jury during a live contest.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DOMJudge is entirely free and open-source under the GPL-2.0 license, with no licensing fees or usage charges from the project.$q$, $q$Organizations only need to budget for their own server and judge-machine infrastructure, since DOMJudge does not offer an official paid hosting or SaaS product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('854f8d2c-af4c-48f6-b7f6-07a0687b0ff0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
